import chalk from "chalk";
import type { ApiResponse } from "../http.js";

/** 全局输出模式 */
let outputJson = false;

export function setJsonMode(enabled: boolean): void {
  outputJson = enabled;
}

export function isJsonMode(): boolean {
  return outputJson;
}

/** JSON 模式直接输出原始 JSON，否则输出格式化内容 */
export function printData(data: unknown): void {
  if (outputJson) {
    console.log(JSON.stringify(data, null, 2));
  } else {
    console.log(JSON.stringify(data, null, 2));
  }
}

/** 打印简单 key-value 表格 */
export function printKeyValue(
  obj: Record<string, unknown>,
  keys?: string[],
): void {
  if (outputJson) {
    console.log(JSON.stringify(obj, null, 2));
    return;
  }

  const entries = keys
    ? keys.map((k) => [k, obj[k]])
    : Object.entries(obj);

  const maxKeyLen = Math.max(...entries.map(([k]) => String(k).length));
  for (const [key, value] of entries) {
    const label = chalk.cyan(String(key).padEnd(maxKeyLen));
    const val = value === null || value === undefined ? chalk.dim("—") : value;
    console.log(`  ${label}  ${val}`);
  }
}

/** 打印列表表格 */
export function printTable(
  rows: Record<string, unknown>[],
  columns: { key: string; label: string; width?: number }[],
): void {
  if (outputJson) {
    console.log(JSON.stringify(rows, null, 2));
    return;
  }

  if (rows.length === 0) {
    console.log(chalk.dim("  (空)"));
    return;
  }

  // 计算列宽
  const widths = columns.map((col) => {
    const dataMax = Math.max(
      ...rows.map((r) => truncateWidth(String(r[col.key] ?? ""), 40)),
    );
    return col.width ?? Math.max(col.label.length, Math.min(dataMax, 40));
  });

  // 表头
  const header = columns
    .map((col, i) => chalk.bold(col.label.padEnd(widths[i])))
    .join("  ");
  console.log(`  ${header}`);
  console.log(`  ${widths.map((w) => "─".repeat(w)).join("──")}`);

  // 数据行
  for (const row of rows) {
    const line = columns
      .map((col, i) => {
        const val = String(row[col.key] ?? "—");
        return truncate(val, widths[i]).padEnd(widths[i]);
      })
      .join("  ");
    console.log(`  ${line}`);
  }
}

/** 处理 API 响应错误 */
export function handleError(res: ApiResponse): void {
  if (outputJson) {
    console.log(JSON.stringify({ error: true, status: res.status, ...((res.data as object) || {}) }, null, 2));
  } else {
    const data = res.data as Record<string, unknown>;
    const msg = data?.error ?? data?.message ?? "请求失败";
    console.error(chalk.red(`错误 [${res.status}]: ${msg}`));
  }
  process.exit(1);
}

/** 成功提示 */
export function printSuccess(msg: string): void {
  if (outputJson) {
    console.log(JSON.stringify({ ok: true, message: msg }));
  } else {
    console.log(chalk.green(`✓ ${msg}`));
  }
}

function truncate(str: string, maxLen: number): string {
  if (str.length <= maxLen) return str;
  return `${str.slice(0, maxLen - 1)}…`;
}

function truncateWidth(str: string, maxLen: number): number {
  return Math.min(str.length, maxLen);
}

