1	/**
2	 * OpenAlex 公开 API 客户端
3	 * 文档: https://docs.openalex.org/
4	 * 无需鉴权，添加 mailto 参数可进入 polite pool（更稳定）
5	 */
6	
7	const BASE = "https://api.openalex.org";
8	const DEFAULT_EMAIL = "wuzhiguocarter@gmail.com";
9	
10	// ---------------------------------------------------------------------------
11	// 类型定义
12	// ---------------------------------------------------------------------------
13	
14	export interface AuthorResult {
15	  openalex_id: string;
16	  display_name: string;
17	  orcid: string | null;
18	  works_count: number;
19	  cited_by_count: number;
20	  institutions: string[];
21	  works_api_url: string | null;
22	}
23	
24	export interface WorkResult {
25	  openalex_id: string;
26	  title: string;
27	  year: number | null;
28	  publication_date: string | null;
29	  type: string | null;
30	  doi: string | null;
31	  journal: string | null;
32	  cited_by_count: number;
33	  is_open_access: boolean;
34	  oa_url: string | null;
35	  authors: string[];
36	  topics: string[];
37	}
38	
39	export interface TagResult {
40	  topics: Array<{
41	    display_name: string;
42	    score: number | null;
43	    field: string | null;
44	    domain: string | null;
45	  }>;
46	  keywords: string[];
47	}
48	
49	// ---------------------------------------------------------------------------
50	// 内部工具函数
51	// ---------------------------------------------------------------------------
52	
53	/** 将 OpenAlex 原始 work dict 规范化为扁平结构 */
54	function extractWork(w: Record<string, unknown>): WorkResult {
55	  let doi = (w["doi"] as string) ?? "";
56	  doi = doi.replace("https://doi.org/", "");
57	
58	  const primary = (w["primary_location"] as Record<string, unknown>) ?? {};
59	  const source = (primary["source"] as Record<string, unknown>) ?? {};
60	  const journal = (source["display_name"] as string) ?? null;
61	
62	  const oa = (w["open_access"] as Record<string, unknown>) ?? {};
63	
64	  const authorships = (w["authorships"] as Array<Record<string, unknown>>) ?? [];
65	  const authors = authorships
66	    .slice(0, 5)
67	    .map((a) => ((a["author"] as Record<string, unknown>)?.["display_name"] as string) ?? "")
68	    .filter(Boolean);
69	
70	  const topicsRaw = (w["topics"] as Array<Record<string, unknown>>) ?? [];
71	  const topics = topicsRaw.slice(0, 3).map((t) => (t["display_name"] as string) ?? "");
72	
73	  return {
74	    openalex_id: (w["id"] as string) ?? "",
75	    title: ((w["title"] as string) ?? "").trim(),
76	    year: (w["publication_year"] as number) ?? null,
77	    publication_date: (w["publication_date"] as string) ?? null,
78	    type: (w["type"] as string) ?? null,
79	    doi: doi || null,
80	    journal,
81	    cited_by_count: (w["cited_by_count"] as number) ?? 0,
82	    is_open_access: (oa["is_oa"] as boolean) ?? false,
83	    oa_url: (oa["oa_url"] as string) ?? null,
84	    authors,
85	    topics,
86	  };
87	}
88	
89	/** 将 OpenAlex 原始 author dict 转为 AuthorResult */
90	function fromApiAuthor(data: Record<string, unknown>): AuthorResult {
91	  const affiliations = (data["affiliations"] as Array<Record<string, unknown>>) ?? [];
92	  let institutions = affiliations
93	    .map((a) => a["display_name"] as string)
94	    .filter(Boolean);
95	
96	  if (institutions.length === 0) {
97	    const lastKnown = (data["last_known_institutions"] as Array<Record<string, unknown>>) ?? [];
98	    institutions = lastKnown.map((i) => i["display_name"] as string).filter(Boolean);
99	  }
100	
101	  const orcidRaw = data["orcid"] as string | null;
102	  const orcid = orcidRaw ? orcidRaw.replace("https://orcid.org/", "").trim() : null;
103	
104	  return {
105	    openalex_id: (data["id"] as string) ?? "",
106	    display_name: (data["display_name"] as string) ?? "",
107	    orcid,
108	    works_count: (data["works_count"] as number) ?? 0,
109	    cited_by_count: (data["cited_by_count"] as number) ?? 0,
110	    institutions: institutions.slice(0, 3),
111	    works_api_url: (data["works_api_url"] as string) ?? null,
112	  };
113	}
114	
115	/** 统一 GET 请求，自动注入 mailto 参数 */
116	async function openAlexGet(
117	  path: string,
118	  params: Record<string, string | number | boolean>,
119	  email = DEFAULT_EMAIL,
120	): Promise<unknown> {
121	  const url = new URL(`${BASE}${path}`);
122	  url.searchParams.set("mailto", email);
123	  for (const [key, value] of Object.entries(params)) {
124	    if (value !== undefined && value !== "") {
125	      url.searchParams.set(key, String(value));
126	    }
127	  }
128	
129	  const res = await fetch(url.toString(), {
130	    headers: {
131	      "User-Agent": `kb-crm-cli/1.0 (mailto:${email})`,
132	      "Accept": "application/json",
133	    },
134	  });
135	
136	  if (!res.ok) {
137	    throw new Error(`OpenAlex API 错误: ${res.status} ${res.statusText}`);
138	  }
139	  return res.json();
140	}
141	
142	// ---------------------------------------------------------------------------
143	// 公开 API
144	// ---------------------------------------------------------------------------
145	
146	/** 按姓名搜索学者（OpenAlex 消歧义）*/
147	export async function searchAuthors(
148	  name: string,
149	  perPage = 10,
150	  email?: string,
151	): Promise<AuthorResult[]> {
152	  const data = (await openAlexGet(
153	    "/authors",
154	    { search: name, "per-page": Math.min(perPage, 25) },
155	    email,
156	  )) as Record<string, unknown>;
157	  const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
158	  return results.map(fromApiAuthor);
159	}
160	
161	/**
162	 * 获取单个学者信息。
163	 * 支持 OpenAlex ID（A1234567890）或 ORCID（0000-0002-xxxx-xxxx）
164	 */
165	export async function getAuthor(
166	  idOrOrcid: string,
167	  email?: string,
168	): Promise<AuthorResult | null> {
169	  const normalized = idOrOrcid.trim();
170	
171	  // 直接通过 OpenAlex ID 查询
172	  if (/^A\d+$/.test(normalized)) {
173	    try {
174	      const data = (await openAlexGet(`/authors/${normalized}`, {}, email)) as Record<string, unknown>;
175	      return fromApiAuthor(data);
176	    } catch {
177	      return null;
178	    }
179	  }
180	
181	  // 通过 ORCID 查询
182	  const orcid = normalized.replace("https://orcid.org/", "");
183	  const data = (await openAlexGet(
184	    "/authors",
185	    { filter: `orcid:${orcid}`, "per-page": 1 },
186	    email,
187	  )) as Record<string, unknown>;
188	  const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
189	  return results.length > 0 ? fromApiAuthor(results[0]) : null;
190	}
191	
192	/** 获取学者逐年发表量统计 */
193	export async function getAuthorStats(
194	  authorId: string,
195	  email?: string,
196	): Promise<Record<string, number>> {
197	  const short = authorId.split("/").at(-1) ?? authorId;
198	  const data = (await openAlexGet(
199	    "/works",
200	    { filter: `author.id:${short}`, group_by: "publication_year", "per-page": 1 },
201	    email,
202	  )) as Record<string, unknown>;
203	  const groups = (data["group_by"] as Array<Record<string, unknown>>) ?? [];
204	  return Object.fromEntries(
205	    groups
206	      .sort((a, b) => Number(a["key"]) - Number(b["key"]))
207	      .map((g) => [String(g["key"]), g["count"] as number]),
208	  );
209	}
210	
211	/** 获取学者发表的论文列表 */
212	export async function getAuthorWorks(
213	  authorId: string,
214	  perPage = 25,
215	  sort = "cited_by_count:desc",
216	  includeXpac = false,
217	  email?: string,
218	): Promise<WorkResult[]> {
219	  const short = authorId.split("/").at(-1) ?? authorId;
220	  const params: Record<string, string | number | boolean> = {
221	    filter: `author.id:${short}`,
222	    "per-page": Math.min(perPage, 50),
223	    sort,
224	  };
225	  if (includeXpac) params["include_xpac"] = "true";
226	  const data = (await openAlexGet("/works", params, email)) as Record<string, unknown>;
227	  const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
228	  return results.map(extractWork);
229	}
230	
231	/**
232	 * 查找与指定论文相关的论文。
233	 * 支持 OpenAlex Work ID（W1234567890）或 DOI（10.xxxx/...）
234	 */
235	export async function getRelatedWorks(
236	  workId: string,
237	  email?: string,
238	): Promise<WorkResult[]> {
239	  let normalized = workId.trim();
240	  if (normalized.startsWith("10.")) {
241	    normalized = `https://doi.org/${normalized}`;
242	  }
243	  try {
244	    const encoded = encodeURIComponent(normalized);
245	    const workData = (await openAlexGet(
246	      `/works/${encoded}`,
247	      { select: "id,related_works" },
248	      email,
249	    )) as Record<string, unknown>;
250	    const relatedIds = (workData["related_works"] as string[]) ?? [];
251	    if (relatedIds.length === 0) return [];
252	
253	    const idsShort = relatedIds.slice(0, 10).map((r) => r.split("/").at(-1)!);
254	    const filterStr = idsShort.join("|");
255	    const data = (await openAlexGet(
256	      "/works",
257	      { filter: `openalex_id:${filterStr}`, "per-page": 10 },
258	      email,
259	    )) as Record<string, unknown>;
260	    const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
261	    return results.map(extractWork);
262	  } catch {
263	    return [];
264	  }
265	}
266	
267	/**
268	 * 语义主题标注：输入标题+摘要，返回自动分配的主题和关键词。
269	 * 适用于没有 DOI 的论文分类。
270	 */
271	export async function tagText(
272	  title: string,
273	  abstract = "",
274	  email?: string,
275	): Promise<TagResult> {
276	  const params: Record<string, string> = { title };
277	  if (abstract) params["abstract"] = abstract;
278	  const data = (await openAlexGet("/text", params, email)) as Record<string, unknown>;
279	
280	  const topicsRaw = (data["topics"] as Array<Record<string, unknown>>) ?? [];
281	  const keywordsRaw = (data["keywords"] as Array<Record<string, unknown>>) ?? [];
282	
283	  return {
284	    topics: topicsRaw.map((t) => ({
285	      display_name: t["display_name"] as string,
286	      score: (t["score"] as number) ?? null,
287	      field: ((t["field"] as Record<string, unknown>)?.["display_name"] as string) ?? null,
288	      domain: ((t["domain"] as Record<string, unknown>)?.["display_name"] as string) ?? null,
289	    })),
290	    keywords: keywordsRaw.map((k) => k["display_name"] as string),
291	  };
292	}
