/**
 * OpenAlex 公开 API 客户端
 * 文档: https://docs.openalex.org/
 * 无需鉴权，添加 mailto 参数可进入 polite pool（更稳定）
 */

const BASE = "https://api.openalex.org";
const DEFAULT_EMAIL = "wuzhiguocarter@gmail.com";

// ---------------------------------------------------------------------------
// 类型定义
// ---------------------------------------------------------------------------

export interface AuthorResult {
  openalex_id: string;
  display_name: string;
  orcid: string | null;
  works_count: number;
  cited_by_count: number;
  institutions: string[];
  works_api_url: string | null;
}

export interface WorkResult {
  openalex_id: string;
  title: string;
  year: number | null;
  publication_date: string | null;
  type: string | null;
  doi: string | null;
  journal: string | null;
  cited_by_count: number;
  is_open_access: boolean;
  oa_url: string | null;
  authors: string[];
  topics: string[];
}

export interface TagResult {
  topics: Array<{
    display_name: string;
    score: number | null;
    field: string | null;
    domain: string | null;
  }>;
  keywords: string[];
}

// ---------------------------------------------------------------------------
// 内部工具函数
// ---------------------------------------------------------------------------

/** 将 OpenAlex 原始 work dict 规范化为扁平结构 */
function extractWork(w: Record<string, unknown>): WorkResult {
  let doi = (w["doi"] as string) ?? "";
  doi = doi.replace("https://doi.org/", "");

  const primary = (w["primary_location"] as Record<string, unknown>) ?? {};
  const source = (primary["source"] as Record<string, unknown>) ?? {};
  const journal = (source["display_name"] as string) ?? null;

  const oa = (w["open_access"] as Record<string, unknown>) ?? {};

  const authorships = (w["authorships"] as Array<Record<string, unknown>>) ?? [];
  const authors = authorships
    .slice(0, 5)
    .map((a) => ((a["author"] as Record<string, unknown>)?.["display_name"] as string) ?? "")
    .filter(Boolean);

  const topicsRaw = (w["topics"] as Array<Record<string, unknown>>) ?? [];
  const topics = topicsRaw.slice(0, 3).map((t) => (t["display_name"] as string) ?? "");

  return {
    openalex_id: (w["id"] as string) ?? "",
    title: ((w["title"] as string) ?? "").trim(),
    year: (w["publication_year"] as number) ?? null,
    publication_date: (w["publication_date"] as string) ?? null,
    type: (w["type"] as string) ?? null,
    doi: doi || null,
    journal,
    cited_by_count: (w["cited_by_count"] as number) ?? 0,
    is_open_access: (oa["is_oa"] as boolean) ?? false,
    oa_url: (oa["oa_url"] as string) ?? null,
    authors,
    topics,
  };
}

/** 将 OpenAlex 原始 author dict 转为 AuthorResult */
function fromApiAuthor(data: Record<string, unknown>): AuthorResult {
  const affiliations = (data["affiliations"] as Array<Record<string, unknown>>) ?? [];
  let institutions = affiliations
    .map((a) => a["display_name"] as string)
    .filter(Boolean);

  if (institutions.length === 0) {
    const lastKnown = (data["last_known_institutions"] as Array<Record<string, unknown>>) ?? [];
    institutions = lastKnown.map((i) => i["display_name"] as string).filter(Boolean);
  }

  const orcidRaw = data["orcid"] as string | null;
  const orcid = orcidRaw ? orcidRaw.replace("https://orcid.org/", "").trim() : null;

  return {
    openalex_id: (data["id"] as string) ?? "",
    display_name: (data["display_name"] as string) ?? "",
    orcid,
    works_count: (data["works_count"] as number) ?? 0,
    cited_by_count: (data["cited_by_count"] as number) ?? 0,
    institutions: institutions.slice(0, 3),
    works_api_url: (data["works_api_url"] as string) ?? null,
  };
}

/** 统一 GET 请求，自动注入 mailto 参数 */
async function openAlexGet(
  path: string,
  params: Record<string, string | number | boolean>,
  email = DEFAULT_EMAIL,
): Promise<unknown> {
  const url = new URL(`${BASE}${path}`);
  url.searchParams.set("mailto", email);
  for (const [key, value] of Object.entries(params)) {
    if (value !== undefined && value !== "") {
      url.searchParams.set(key, String(value));
    }
  }

  const res = await fetch(url.toString(), {
    headers: {
      "User-Agent": `kb-crm-cli/1.0 (mailto:${email})`,
      "Accept": "application/json",
    },
  });

  if (!res.ok) {
    throw new Error(`OpenAlex API 错误: ${res.status} ${res.statusText}`);
  }
  return res.json();
}

// ---------------------------------------------------------------------------
// 公开 API
// ---------------------------------------------------------------------------

/** 按姓名搜索学者（OpenAlex 消歧义）*/
export async function searchAuthors(
  name: string,
  perPage = 10,
  email?: string,
): Promise<AuthorResult[]> {
  const data = (await openAlexGet(
    "/authors",
    { search: name, "per-page": Math.min(perPage, 25) },
    email,
  )) as Record<string, unknown>;
  const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
  return results.map(fromApiAuthor);
}

/**
 * 获取单个学者信息。
 * 支持 OpenAlex ID（A1234567890）或 ORCID（0000-0002-xxxx-xxxx）
 */
export async function getAuthor(
  idOrOrcid: string,
  email?: string,
): Promise<AuthorResult | null> {
  const normalized = idOrOrcid.trim();

  // 直接通过 OpenAlex ID 查询
  if (/^A\d+$/.test(normalized)) {
    try {
      const data = (await openAlexGet(`/authors/${normalized}`, {}, email)) as Record<string, unknown>;
      return fromApiAuthor(data);
    } catch {
      return null;
    }
  }

  // 通过 ORCID 查询
  const orcid = normalized.replace("https://orcid.org/", "");
  const data = (await openAlexGet(
    "/authors",
    { filter: `orcid:${orcid}`, "per-page": 1 },
    email,
  )) as Record<string, unknown>;
  const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
  return results.length > 0 ? fromApiAuthor(results[0]) : null;
}

/** 获取学者逐年发表量统计 */
export async function getAuthorStats(
  authorId: string,
  email?: string,
): Promise<Record<string, number>> {
  const short = authorId.split("/").at(-1) ?? authorId;
  const data = (await openAlexGet(
    "/works",
    { filter: `author.id:${short}`, group_by: "publication_year", "per-page": 1 },
    email,
  )) as Record<string, unknown>;
  const groups = (data["group_by"] as Array<Record<string, unknown>>) ?? [];
  return Object.fromEntries(
    groups
      .sort((a, b) => Number(a["key"]) - Number(b["key"]))
      .map((g) => [String(g["key"]), g["count"] as number]),
  );
}

/** 获取学者发表的论文列表 */
export async function getAuthorWorks(
  authorId: string,
  perPage = 25,
  sort = "cited_by_count:desc",
  includeXpac = false,
  email?: string,
): Promise<WorkResult[]> {
  const short = authorId.split("/").at(-1) ?? authorId;
  const params: Record<string, string | number | boolean> = {
    filter: `author.id:${short}`,
    "per-page": Math.min(perPage, 50),
    sort,
  };
  if (includeXpac) params["include_xpac"] = "true";
  const data = (await openAlexGet("/works", params, email)) as Record<string, unknown>;
  const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
  return results.map(extractWork);
}

/**
 * 查找与指定论文相关的论文。
 * 支持 OpenAlex Work ID（W1234567890）或 DOI（10.xxxx/...）
 */
export async function getRelatedWorks(
  workId: string,
  email?: string,
): Promise<WorkResult[]> {
  let normalized = workId.trim();
  if (normalized.startsWith("10.")) {
    normalized = `https://doi.org/${normalized}`;
  }
  try {
    const encoded = encodeURIComponent(normalized);
    const workData = (await openAlexGet(
      `/works/${encoded}`,
      { select: "id,related_works" },
      email,
    )) as Record<string, unknown>;
    const relatedIds = (workData["related_works"] as string[]) ?? [];
    if (relatedIds.length === 0) return [];

    const idsShort = relatedIds.slice(0, 10).map((r) => r.split("/").at(-1)!);
    const filterStr = idsShort.join("|");
    const data = (await openAlexGet(
      "/works",
      { filter: `openalex_id:${filterStr}`, "per-page": 10 },
      email,
    )) as Record<string, unknown>;
    const results = (data["results"] as Array<Record<string, unknown>>) ?? [];
    return results.map(extractWork);
  } catch {
    return [];
  }
}

/**
 * 语义主题标注：输入标题+摘要，返回自动分配的主题和关键词。
 * 适用于没有 DOI 的论文分类。
 */
export async function tagText(
  title: string,
  abstract = "",
  email?: string,
): Promise<TagResult> {
  const params: Record<string, string> = { title };
  if (abstract) params["abstract"] = abstract;
  const data = (await openAlexGet("/text", params, email)) as Record<string, unknown>;

  const topicsRaw = (data["topics"] as Array<Record<string, unknown>>) ?? [];
  const keywordsRaw = (data["keywords"] as Array<Record<string, unknown>>) ?? [];

  return {
    topics: topicsRaw.map((t) => ({
      display_name: t["display_name"] as string,
      score: (t["score"] as number) ?? null,
      field: ((t["field"] as Record<string, unknown>)?.["display_name"] as string) ?? null,
      domain: ((t["domain"] as Record<string, unknown>)?.["display_name"] as string) ?? null,
    })),
    keywords: keywordsRaw.map((k) => k["display_name"] as string),
  };
}

