/**
 * scholar 命令组 — 学者与论文检索（OpenAlex）
 *
 * 子命令：
 *   search <name>         按姓名搜索学者，返回 ORCID 和统计信息
 *   profile <orcid|id>    查看学者详情
 *   works <orcid|id>      获取论文列表（按被引/日期排序）
 *   related <doi|work-id> 查找相关论文
 *   tag <title>           语义主题标注
 */

import { Command } from "commander";
import {
  getAuthor,
  getAuthorStats,
  getAuthorWorks,
  getRelatedWorks,
  searchAuthors,
  tagText,
} from "../core/openalex.js";
import { isJsonMode, printTable } from "../utils/output.js";

export function registerScholarCommands(program: Command): void {
  const scholar = program
    .command("scholar")
    .description("学者与论文检索（OpenAlex）");

  // ---------------------------------------------------------------------------
  // search
  // ---------------------------------------------------------------------------
  scholar
    .command("search <name>")
    .description("按姓名搜索学者，返回 ORCID 和机构信息")
    .option("-n, --limit <n>", "最大返回数量", "10")
    .option("--email <email>", "OpenAlex polite pool 邮箱")
    .action(async (name: string, opts) => {
      try {
        const authors = await searchAuthors(name, Number(opts.limit), opts.email);

        if (isJsonMode()) {
          console.log(JSON.stringify(authors, null, 2));
          return;
        }

        if (authors.length === 0) {
          console.log("未找到相关学者。");
          return;
        }

        printTable(
          authors.map((a, i) => ({
            "#": i + 1,
            name: a.display_name,
            orcid: a.orcid ?? "—",
            works: a.works_count,
            citations: a.cited_by_count,
            affiliation: a.institutions.join(", ") || "—",
          })),
          [
            { key: "#", label: "#", width: 3 },
            { key: "name", label: "姓名", width: 20 },
            { key: "orcid", label: "ORCID", width: 20 },
            { key: "works", label: "论文数", width: 6 },
            { key: "citations", label: "被引", width: 8 },
            { key: "affiliation", label: "机构", width: 35 },
          ],
        );
        console.log(`\n共 ${authors.length} 条结果。使用 --json 获取机器可读输出。`);
        console.log(`提示：复制 ORCID 并运行 \`kb-crm scholar works <orcid>\``);
      } catch (err) {
        console.error(`错误: ${err instanceof Error ? err.message : String(err)}`);
        process.exit(1);
      }
    });

  // ---------------------------------------------------------------------------
  // profile
  // ---------------------------------------------------------------------------
  scholar
    .command("profile <orcid_or_id>")
    .description("查看学者详情（支持 ORCID 或 OpenAlex ID）")
    .option("--stats", "显示逐年发表统计")
    .option("--email <email>", "OpenAlex polite pool 邮箱")
    .action(async (orcidOrId: string, opts) => {
      try {
        const author = await getAuthor(orcidOrId, opts.email);
        if (!author) {
          console.error(`未找到学者: ${orcidOrId}`);
          process.exit(1);
        }

        let timeline: Record<string, number> | null = null;
        if (opts.stats) {
          timeline = await getAuthorStats(author.openalex_id, opts.email);
        }

        if (isJsonMode()) {
          const out: Record<string, unknown> = { ...author };
          if (timeline) out["yearly_works"] = timeline;
          console.log(JSON.stringify(out, null, 2));
          return;
        }

        console.log(`OpenAlex ID:  ${author.openalex_id}`);
        console.log(`姓名:         ${author.display_name}`);
        console.log(`ORCID:        ${author.orcid ?? "—"}`);
        console.log(`论文数:       ${author.works_count}`);
        console.log(`被引次数:     ${author.cited_by_count.toLocaleString()}`);
        if (author.institutions.length > 0) {
          console.log(`机构:         ${author.institutions.join(", ")}`);
        }
        if (timeline) {
          console.log("\n逐年发表量：");
          const entries = Object.entries(timeline).slice(-10);
          for (const [year, count] of entries) {
            const bar = "█".repeat(Math.min(count, 40));
            console.log(`  ${year}  ${bar} ${count}`);
          }
        }
      } catch (err) {
        console.error(`错误: ${err instanceof Error ? err.message : String(err)}`);
        process.exit(1);
      }
    });

  // ---------------------------------------------------------------------------
  // works
  // ---------------------------------------------------------------------------
  scholar
    .command("works <orcid_or_id>")
    .description("获取学者发表的论文列表")
    .option("-n, --limit <n>", "最大获取数量", "25")
    .option(
      "--sort <sort>",
      "排序方式: citations（被引数，默认）| date（最新优先）",
      "citations",
    )
    .option("--xpac", "包含 XPAC 扩展数据集（+1.9亿论文，质量较低）")
    .option("--email <email>", "OpenAlex polite pool 邮箱")
    .action(async (orcidOrId: string, opts) => {
      try {
        const author = await getAuthor(orcidOrId, opts.email);
        if (!author) {
          console.error(`未找到学者: ${orcidOrId}`);
          process.exit(1);
        }

        const sortParam =
          opts.sort === "date" ? "publication_date:desc" : "cited_by_count:desc";
        const works = await getAuthorWorks(
          author.openalex_id,
          Number(opts.limit),
          sortParam,
          opts.xpac ?? false,
          opts.email,
        );

        if (isJsonMode()) {
          console.log(JSON.stringify(works, null, 2));
          return;
        }

        console.log(
          `学者: ${author.display_name}  |  总论文数: ${author.works_count.toLocaleString()}\n`,
        );
        printTable(
          works.map((w, i) => ({
            "#": i + 1,
            year: w.year ?? "—",
            title: w.title,
            type: w.type ?? "—",
            cited: w.cited_by_count,
            oa: w.is_open_access ? "OA" : "",
          })),
          [
            { key: "#", label: "#", width: 3 },
            { key: "year", label: "年份", width: 4 },
            { key: "title", label: "标题", width: 50 },
            { key: "type", label: "类型", width: 12 },
            { key: "cited", label: "被引", width: 6 },
            { key: "oa", label: "OA", width: 2 },
          ],
        );
      } catch (err) {
        console.error(`错误: ${err instanceof Error ? err.message : String(err)}`);
        process.exit(1);
      }
    });

  // ---------------------------------------------------------------------------
  // related
  // ---------------------------------------------------------------------------
  scholar
    .command("related <doi_or_id>")
    .description("查找相关论文（支持 DOI 或 OpenAlex Work ID）")
    .option("--email <email>", "OpenAlex polite pool 邮箱")
    .action(async (doiOrId: string, opts) => {
      try {
        const related = await getRelatedWorks(doiOrId, opts.email);

        if (related.length === 0) {
