            return
        click.echo("主题标签：")
        rows = [
            {
                "topic": t.display_name,
                "field": t.field or "—",
                "domain": t.domain or "—",
                "score": f"{t.score:.3f}" if t.score is not None else "—",
            }
            for t in result.topics
        ]
        print_table(rows, [
            {"key": "topic", "label": "主题", "width": 30},
            {"key": "field", "label": "领域", "width": 20},
            {"key": "domain", "label": "大类", "width": 20},
